void run_test_case(const std::vector<int>& arr_vec, int expected_min, int expected_max) {
    int size = arr_vec.size();
    int* arr = nullptr;
    if (size > 0) {
        arr = new int[size];
        for (int i = 0; i < size; ++i) {
            arr[i] = arr_vec[i];
        }
    }

    int min_val, max_val;
    // Initialize to arbitrary values to ensure they are set by the function
    min_val = 999999;
    max_val = -999999;

    findMinMax(arr, size, min_val, max_val);

    std::stringstream ss_input;
    ss_input << "{";
    for (size_t i = 0; i < arr_vec.size(); ++i) {
        ss_input << arr_vec[i] << (i == arr_vec.size() - 1 ? "" : ", ");
    }
    ss_input << "}";

    std::cout << "Input Array: " << ss_input.str() << std::endl;
    std::cout << "Observed Min: " << min_val << ", Max: " << max_val << std::endl;
    std::cout << "Expected Min: " << expected_min << ", Max: " << expected_max << std::endl;
    std::cout << "---\n";

    if (size > 0) {
        delete[] arr;
    }
}

